import { useState, useEffect, useRef, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Drawer, DrawerContent, DrawerHeader, DrawerTitle } from "@/components/ui/drawer";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Skeleton } from "@/components/ui/skeleton";
import { useIsMobile } from "@/hooks/use-mobile";
import { AIRecipeSuggestion } from "@/hooks/useAIRecipe";
// useRecipeVideo removed - only using background video tasks now
import { useWatermarkedVideo } from "@/hooks/useWatermarkedVideo";
import { useVideoTasks } from "@/contexts/VideoTaskContext";
import RecipeCookingMode from "@/components/community/recipe/RecipeCookingMode";
import AnimatedLoadingText from "@/components/ai-recipe/AnimatedLoadingText";
import { Clock, Users, ChefHat, PlayCircle, List, Utensils, Bookmark, Sparkles, Image, Video, Loader2, Download, Share2, Globe } from "lucide-react";
import xiaoxiongLogo from "@/assets/xiaoxiong-logo-clean.png";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";

const IMAGE_URL = `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/ai-recipe/generate-images`;

// Languages that have pre-generated columns (zh, en, pt)
const PRE_GENERATED_LANGS = ["zh", "en", "pt"];

interface TranslatedRecipe {
  recipe_name?: string;
  introduction?: string;
  subtitle?: string;
  ingredients?: Array<{ name: string; unit: string }>;
  steps?: Array<{ description: string }>;
}

interface SavedRecipeDetailDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  recipe: AIRecipeSuggestion | null;
  recipeName: string;
  onSave?: (recipe: AIRecipeSuggestion) => void;
  isSaving?: boolean;
  isSaved?: boolean;
  initialImageUrl?: string | null;
  /** Enable video generation button inside the dialog */
  enableVideoGeneration?: boolean;
}

type ViewMode = "guided" | "full";
type GuidedPhase = "overview" | "cooking";

const buildVideoPrompt = (recipe: AIRecipeSuggestion): string => {
  const steps = recipe.steps || [];
  // Include ALL steps word-for-word, no truncation
  const stepDescriptions = steps
    .map((s: any, i: number) => `Step ${i + 1}: ${s.description_en || s.description || ""}`)
    .filter((s: string) => s.length > 7) // filter empty "Step N: "
    .join(". ");
  const dishName = recipe.recipe_name_en || recipe.recipe_name;
  return `Step-by-step cooking tutorial video showing the complete preparation process of ${dishName}. ${stepDescriptions}. Kitchen counter with fresh ingredients, cutting board, knife, pots and pans visible. Warm natural kitchen lighting, steam rising from the pan, close-up of each cooking step, smooth transitions between steps. --duration 5 --camerafixed true`;
};

const SavedRecipeDetailDialog = ({ open, onOpenChange, recipe, recipeName, onSave, isSaving, isSaved, initialImageUrl, enableVideoGeneration }: SavedRecipeDetailDialogProps) => {
  const { t, i18n } = useTranslation();
  const isMobile = useIsMobile();
  const navigate = useNavigate();
  const [viewMode, setViewMode] = useState<ViewMode>("guided");
  const [guidedPhase, setGuidedPhase] = useState<GuidedPhase>("overview");
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [imageLoading, setImageLoading] = useState(false);
  const fetchedRef = useRef<string | null>(null);

  // Video generation - uses global background context
  const { addTask: addBgVideoTask, tasks: bgTasks, setTaskWatermarkedUrl } = useVideoTasks();
  // Only track video generated during THIS dialog session (not previous ones)
  const [sessionVideoUrl, setSessionVideoUrl] = useState<string | null>(null);
  const sessionTaskIdRef = useRef<string | null>(null);
  // Optimistic flag: immediately show "processing" UI when button is clicked
  const [isVideoRequested, setIsVideoRequested] = useState(false);

  // Find bg task for this session only
  const sessionBgTask = sessionTaskIdRef.current
    ? bgTasks.find(t => t.id === sessionTaskIdRef.current)
    : null;
  const isBgVideoProcessing = isVideoRequested || sessionBgTask?.status === "creating" || sessionBgTask?.status === "processing";
  const isBgVideoFailed = sessionBgTask?.status === "failed";

  // When dialog opens, try to match a completed bg task for this recipe
  useEffect(() => {
    if (!open || !recipe || sessionTaskIdRef.current) return;
    const matchedTask = bgTasks.find(
      t => t.status === "succeeded" && t.videoUrl && t.recipeName === recipe.recipe_name
    );
    if (matchedTask) {
      sessionTaskIdRef.current = matchedTask.id;
      // Use watermarked URL if already processed, otherwise raw URL
      setSessionVideoUrl(matchedTask.watermarkedVideoUrl || matchedTask.videoUrl);
      console.log(`[Dialog] Auto-matched completed task ${matchedTask.id}, watermarked=${!!matchedTask.watermarkedVideoUrl}`);
    }
  }, [open, recipe?.recipe_name, bgTasks]);

  // When session bg task succeeds or fails, clear optimistic flag and capture URL
  useEffect(() => {
    if (sessionBgTask?.status === "succeeded" || sessionBgTask?.status === "failed") {
      setIsVideoRequested(false);
    }
    if (sessionBgTask?.status === "succeeded" && sessionBgTask.videoUrl && !sessionVideoUrl) {
      setSessionVideoUrl(sessionBgTask.watermarkedVideoUrl || sessionBgTask.videoUrl);
    }
  }, [sessionBgTask?.status, sessionBgTask?.videoUrl, sessionBgTask?.watermarkedVideoUrl, sessionVideoUrl]);

  // Determine if we need client-side watermarking (only for raw URLs, skip if already watermarked)
  const needsWatermarking = sessionVideoUrl && !sessionVideoUrl.includes("/watermarked/");
  const videoForWatermark = needsWatermarking ? sessionVideoUrl : null;
  const hasVideo = !!sessionVideoUrl;
  const { watermarkedUrl, isMp4 } = useWatermarkedVideo(videoForWatermark, xiaoxiongLogo);
  const isWatermarking = needsWatermarking && !watermarkedUrl;

  // After client-side watermarking completes, upload to storage and update the task
  const watermarkUploadedRef = useRef<string | null>(null);
  useEffect(() => {
    if (!watermarkedUrl || !sessionTaskIdRef.current) return;
    if (watermarkUploadedRef.current === watermarkedUrl) return;
    watermarkUploadedRef.current = watermarkedUrl;

    const taskId = sessionTaskIdRef.current;
    const uploadWatermarked = async () => {
      try {
        const blob = await fetch(watermarkedUrl).then(r => r.blob());
        const task = bgTasks.find(t => t.id === taskId);
        if (!task?.taskId) return;

        const ext = isMp4 ? "mp4" : "webm";
        const filePath = `watermarked/${task.taskId}-${Date.now()}.${ext}`;
        const { error } = await supabase.storage
          .from("ai-recipe-videos")
          .upload(filePath, blob, {
            contentType: isMp4 ? "video/mp4" : "video/webm",
            upsert: true,
          });
        if (error) {
          console.error("[Dialog] Watermark upload error:", error);
          return;
        }
        const { data: publicUrlData } = supabase.storage
          .from("ai-recipe-videos")
          .getPublicUrl(filePath);
        const storageUrl = publicUrlData.publicUrl;
        console.log(`[Dialog] Watermarked video uploaded: ${storageUrl}`);

        // Update context task and local state so future opens skip re-processing
        setTaskWatermarkedUrl(taskId, storageUrl);
        setSessionVideoUrl(storageUrl);
      } catch (err) {
        console.error("[Dialog] Watermark upload failed:", err);
      }
    };
    uploadWatermarked();
  }, [watermarkedUrl, isMp4, bgTasks, setTaskWatermarkedUrl]);

  // On-demand translation for non-pre-generated languages
  const [isTranslating, setIsTranslating] = useState(false);
  const [translatedRecipe, setTranslatedRecipe] = useState<TranslatedRecipe | null>(null);
  const translationLangRef = useRef<string | null>(null);

  const needsTranslation = !PRE_GENERATED_LANGS.includes(i18n.language);

  const translateField = useCallback(async (text: string, targetLang: string): Promise<string> => {
    if (!text) return "";
    try {
      const { data, error } = await supabase.functions.invoke("translate-content", {
        body: { text, targetLang },
      });
      if (error || !data?.translatedText) return text;
      return data.translatedText;
    } catch {
      return text;
    }
  }, []);

  useEffect(() => {
    if (!open || !recipe || !needsTranslation) {
      setTranslatedRecipe(null);
      translationLangRef.current = null;
      return;
    }
    if (translationLangRef.current === `${i18n.language}_${recipe.recipe_name}`) return;
    translationLangRef.current = `${i18n.language}_${recipe.recipe_name}`;

    const doTranslate = async () => {
      setIsTranslating(true);
      try {
        const lang = i18n.language;
        const sourceName = recipe.recipe_name_en || recipe.recipe_name;
        const sourceIntro = (recipe as any).introduction_en || (recipe as any).introduction || "";
        const sourceSubtitle = recipe.subtitle_en || recipe.subtitle || "";

        const [trName, trIntro, trSubtitle] = await Promise.all([
          sourceName ? translateField(sourceName, lang) : Promise.resolve(""),
          sourceIntro ? translateField(sourceIntro, lang) : Promise.resolve(""),
          sourceSubtitle ? translateField(sourceSubtitle, lang) : Promise.resolve(""),
        ]);

        // Translate ingredients
        let trIngredients: Array<{ name: string; unit: string }> | undefined;
        if (recipe.ingredients?.length) {
          const names = recipe.ingredients.map(i => i.name_en || i.name || "").join("\n");
          const units = recipe.ingredients.map(i => i.unit_en || i.unit || "").join("\n");
          const [trNames, trUnits] = await Promise.all([
            names ? translateField(names, lang) : Promise.resolve(""),
            units ? translateField(units, lang) : Promise.resolve(""),
          ]);
          const nameArr = trNames.split("\n");
          const unitArr = trUnits.split("\n");
          trIngredients = recipe.ingredients.map((_, idx) => ({
            name: nameArr[idx] || "",
            unit: unitArr[idx] || "",
          }));
        }

        // Translate steps
        let trSteps: Array<{ description: string }> | undefined;
        if (recipe.steps?.length) {
          const descs = recipe.steps.map(s => s.description_en || s.description || "").join("\n---\n");
          const trDescs = descs ? await translateField(descs, lang) : "";
          const descArr = trDescs.split("\n---\n");
          trSteps = recipe.steps.map((_, idx) => ({
            description: descArr[idx] || "",
          }));
        }

        setTranslatedRecipe({
          recipe_name: trName,
          introduction: trIntro,
          subtitle: trSubtitle,
          ingredients: trIngredients,
          steps: trSteps,
        });
      } catch (err) {
        console.error("[SavedRecipeDetailDialog] Translation error:", err);
      } finally {
        setIsTranslating(false);
      }
    };
    doTranslate();
  }, [open, recipe?.recipe_name, i18n.language, needsTranslation]);

  // Load image
  useEffect(() => {
    if (!open || !recipe) return;
    if (initialImageUrl) {
      setImageUrl(initialImageUrl);
      setImageLoading(false);
      return;
    }
    if (recipe.image_url) {
      setImageUrl(recipe.image_url as string);
      setImageLoading(false);
      return;
    }
    if (fetchedRef.current === recipe.recipe_name) return;
    fetchedRef.current = recipe.recipe_name;
    setImageLoading(true);
    setImageUrl(null);
    fetch(IMAGE_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY}`,
      },
      body: JSON.stringify({ recipes: [{ recipe_name: recipe.recipe_name, recipe_name_en: recipe.recipe_name_en }] }),
    })
      .then(r => r.json())
      .then(data => {
        const url = data.images?.[0]?.image_url || null;
        setImageUrl(url);
      })
      .catch(() => setImageUrl(null))
      .finally(() => setImageLoading(false));
  }, [open, recipe, initialImageUrl]);

  if (!recipe) return null;

  const getName = () => {
    if (needsTranslation && translatedRecipe?.recipe_name) return translatedRecipe.recipe_name;
    if (i18n.language === "en" && recipe.recipe_name_en) return recipe.recipe_name_en;
    if (i18n.language === "pt" && recipe.recipe_name_pt) return recipe.recipe_name_pt;
    if (i18n.language !== "zh" && recipe.recipe_name_en) return recipe.recipe_name_en;
    return recipe.recipe_name;
  };

  const getIntroduction = () => {
    if (needsTranslation && translatedRecipe?.introduction) return translatedRecipe.introduction;
    if (i18n.language === "en" && (recipe as any).introduction_en) return (recipe as any).introduction_en;
    if (i18n.language === "pt" && (recipe as any).introduction_pt) return (recipe as any).introduction_pt;
    return (recipe as any).introduction;
  };

  const getIngredientName = (ing: any, index: number) => {
    if (needsTranslation && translatedRecipe?.ingredients?.[index]?.name) return translatedRecipe.ingredients[index].name;
    if (i18n.language === "en" && ing.name_en) return ing.name_en;
    if (i18n.language === "pt" && ing.name_pt) return ing.name_pt;
    return ing.name;
  };

  const getIngredientUnit = (ing: any, index: number) => {
    if (needsTranslation && translatedRecipe?.ingredients?.[index]?.unit) return translatedRecipe.ingredients[index].unit;
    if (i18n.language === "en" && ing.unit_en) return ing.unit_en;
    if (i18n.language === "pt" && ing.unit_pt) return ing.unit_pt;
    return ing.unit;
  };

  const getStepDescription = (step: any, index: number) => {
    if (needsTranslation && translatedRecipe?.steps?.[index]?.description) return translatedRecipe.steps[index].description;
    if (i18n.language === "en" && step.description_en) return step.description_en;
    if (i18n.language === "pt" && step.description_pt) return step.description_pt;
    return step.description;
  };

  const getDifficultyColor = (d: string) => {
    switch (d) {
      case "easy": return "bg-green-500/20 text-green-700 dark:text-green-400 border-green-500/30";
      case "medium": return "bg-yellow-500/20 text-yellow-700 dark:text-yellow-400 border-yellow-500/30";
      case "hard": return "bg-red-500/20 text-red-700 dark:text-red-400 border-red-500/30";
      default: return "bg-muted text-muted-foreground";
    }
  };

  const getDifficultyLabel = (d: string) => {
    switch (d) {
      case "easy": return t("recipe.difficulty.easy", "简单");
      case "medium": return t("recipe.difficulty.medium", "中等");
      case "hard": return t("recipe.difficulty.hard", "困难");
      default: return d;
    }
  };

  const steps = recipe.steps?.map((s, i) => ({
    order: s.order || i + 1,
    description: s.description,
    description_en: s.description_en,
    description_pt: s.description_pt,
    image_url: undefined as string | undefined,
    image_urls: undefined as string[] | undefined,
  })) || [];

  const hasSteps = steps.length > 0;

  const handleStartCooking = () => {
    setGuidedPhase("cooking");
  };

  const handleOpenChange = (o: boolean) => {
    if (!o) {
      setViewMode("guided");
      setGuidedPhase("overview");
      setImageUrl(null);
      setImageLoading(false);
      fetchedRef.current = null;
      // Reset session video state
      setSessionVideoUrl(null);
      sessionTaskIdRef.current = null;
      watermarkUploadedRef.current = null;
      setIsVideoRequested(false);
    }
    onOpenChange(o);
  };

  const handleGenerateVideo = async () => {
    if (!recipe || !imageUrl) return;
    // Optimistic: immediately show processing state
    setIsVideoRequested(true);
    const prompt = buildVideoPrompt(recipe);
    const taskId = await addBgVideoTask(recipe.recipe_name, recipe.recipe_name_en, imageUrl, prompt, recipe);
    if (taskId) {
      sessionTaskIdRef.current = taskId;
      toast.success(t("videoTask.addedToQueue", "视频已开始在后台生成"));
    } else {
      setIsVideoRequested(false);
      toast.error(t("videoTask.maxConcurrent", "最多同时生成 2 个视频，请稍后再试"));
    }
  };

  const handleDownloadVideo = () => {
    const url = watermarkedUrl || sessionVideoUrl;
    if (!url) return;
    const ext = watermarkedUrl ? (isMp4 ? "mp4" : "webm") : "mp4";
    const a = document.createElement("a");
    a.href = url;
    a.download = `${recipe.recipe_name}-xiaoxiong.${ext}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    toast.success(t("aiRecipe.video.downloadComplete", "视频下载完成"));
  };

  const handleShareAsPost = () => {
    const videoUrlToShare = watermarkedUrl || sessionVideoUrl;
    const displayName = getName();
    // Navigate to community with pre-filled post content, including recipe source
    navigate("/community", {
      state: {
        openCreatePost: true,
        prefillPostType: "post",
        prefillContent: `🍳 ${displayName}`,
        prefillVideoUrl: videoUrlToShare,
        prefillAiRecipeSource: recipe ? {
          source: "video_share",
          recipe_name: recipe.recipe_name,
          recipe_name_en: recipe.recipe_name_en || null,
          recipe_name_pt: recipe.recipe_name_pt || null,
          cook_time: recipe.cook_time,
          difficulty: recipe.difficulty,
          servings: recipe.servings,
          ingredients: recipe.ingredients,
          steps: recipe.steps,
          introduction: recipe.introduction,
          introduction_en: recipe.introduction_en || null,
          introduction_pt: recipe.introduction_pt || null,
          subtitle: recipe.subtitle || null,
          subtitle_en: recipe.subtitle_en || null,
          subtitle_pt: recipe.subtitle_pt || null,
          image_url: imageUrl || recipe.image_url || null,
        } : null,
      },
    });
    handleOpenChange(false);
  };

  // Mode toggle
  const ModeToggle = () => (
    <div className="flex justify-end mb-4">
      <div className="inline-flex h-9 items-center rounded-md bg-muted p-1 text-muted-foreground">
        <button
          onClick={() => { setViewMode("guided"); setGuidedPhase("overview"); }}
          className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium transition-all gap-1.5 ${
            viewMode === "guided" ? "bg-background text-foreground shadow-sm" : ""
          }`}
        >
          <PlayCircle className="h-4 w-4" />
          {t("recipe.guidedMode", "流程模式")}
        </button>
        <button
          onClick={() => setViewMode("full")}
          className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium transition-all gap-1.5 ${
            viewMode === "full" ? "bg-background text-foreground shadow-sm" : ""
          }`}
        >
          <List className="h-4 w-4" />
          {t("recipe.fullMode", "完整模式")}
        </button>
      </div>
    </div>
  );

  const CookingContent = () => (
    <Card className="overflow-hidden">
      <RecipeCookingMode
        steps={steps}
        onExit={() => setGuidedPhase("overview")}
      />
    </Card>
  );

  // Media area: video (if generated) or image
  // Determine the best video URL to display: prefer watermarked, fall back to raw
  const displayVideoUrl = watermarkedUrl || sessionVideoUrl;

  const MediaArea = () => {
    // Video succeeded - show video immediately (raw first, watermarked replaces silently)
    if (hasVideo) {
      return (
        <div className="relative w-full aspect-[16/9] bg-muted overflow-hidden">
          <video
            key={displayVideoUrl}
            src={displayVideoUrl!}
            controls
            autoPlay
            muted
            loop
            playsInline
            className="w-full h-full object-cover"
          />
          {/* Silent watermark processing indicator - small corner icon only, no text */}
          {isWatermarking && (
            <div className="absolute top-2 right-2 bg-black/40 rounded-full p-1.5">
              <Loader2 className="h-3.5 w-3.5 animate-spin text-white/80" />
            </div>
          )}
        </div>
      );
    }

    // Background processing: show image with loading overlay
    if (isBgVideoProcessing) {
      return (
        <div className="relative w-full aspect-[16/9] bg-muted overflow-hidden">
          {imageUrl ? (
            <img src={imageUrl} alt={getName()} className="w-full h-full object-cover opacity-60" />
          ) : (
            <Skeleton className="absolute inset-0 w-full h-full rounded-none" />
          )}
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-center space-y-2">
              <Loader2 className="h-6 w-6 animate-spin text-primary mx-auto" />
              <p className="text-xs text-muted-foreground">
                {t("videoTask.processingInBg", "视频正在后台生成，可在右上角查看进度")}
              </p>
            </div>
          </div>
        </div>
      );
    }

    // Default: image
    return (
      <div className="relative w-full aspect-[16/9] bg-muted overflow-hidden">
        {imageLoading ? (
          <>
            <Skeleton className="absolute inset-0 w-full h-full rounded-none" />
            <div className="absolute inset-0 flex flex-col items-center justify-center gap-1.5 z-10">
              <Sparkles className="h-4 w-4 text-primary animate-pulse" />
              <span className="text-xs text-muted-foreground">
                {t("aiRecipe.generatingImage", "AI 正在生成图片...")}
              </span>
            </div>
          </>
        ) : imageUrl ? (
          <img src={imageUrl} alt={getName()} className="w-full h-full object-cover" />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center">
            <Image className="h-10 w-10 text-muted-foreground/30" />
          </div>
        )}
      </div>
    );
  };

  // Video action buttons (below media area when enableVideoGeneration)
  const VideoActions = () => {
    if (!enableVideoGeneration) return null;

    // Video ready - download & share
    if (hasVideo && !isWatermarking) {
      return (
        <div className="flex gap-2 px-4 pt-3">
          <Button variant="outline" size="sm" className="gap-1.5 flex-1" onClick={handleDownloadVideo}>
            <Download className="h-3.5 w-3.5" />
            {t("aiRecipe.video.downloadWithWatermark", "下载视频")}
          </Button>
          <Button variant="outline" size="sm" className="gap-1.5 flex-1" onClick={handleShareAsPost}>
            <Share2 className="h-3.5 w-3.5" />
            {t("aiRecipe.video.shareAsPost", "分享到社区")}
          </Button>
        </div>
      );
    }

    // Video failed
    if (isBgVideoFailed) {
      return (
        <div className="px-4 pt-3 space-y-1.5">
          <p className="text-xs text-destructive text-center">
            {sessionBgTask?.error || t("aiRecipe.video.failed", "视频生成失败")}
          </p>
          <Button variant="outline" size="sm" className="gap-1.5 w-full" onClick={handleGenerateVideo}>
            <Video className="h-3.5 w-3.5" />
            {t("aiRecipe.video.retry", "重新生成视频")}
          </Button>
        </div>
      );
    }

    // Background processing
    if (isBgVideoProcessing) {
      return (
        <div className="px-4 pt-3">
          <div className="flex items-center justify-center gap-2 py-2 text-xs text-muted-foreground">
            <Loader2 className="h-3.5 w-3.5 animate-spin" />
            {t("videoTask.processingInBg", "视频正在后台生成，可在右上角查看进度")}
          </div>
        </div>
      );
    }

    // Not yet generated & not loading
    if (!isBgVideoProcessing && !hasVideo && imageUrl) {
      return (
        <div className="px-4 pt-3">
          <Button variant="outline" size="sm" className="gap-1.5 w-full" onClick={handleGenerateVideo}>
            <Video className="h-3.5 w-3.5" />
            {t("aiRecipe.video.generate", "做视频")}
          </Button>
        </div>
      );
    }

    return null;
  };

  const OverviewContent = () => (
    <Card className="overflow-hidden">
      <MediaArea />
      <VideoActions />

      <CardHeader className="pb-3">
        <div className="flex items-center gap-2 mb-2">
          <Badge className="bg-primary text-primary-foreground gap-1">
            <Utensils className="h-3 w-3" />
            {t("recipe.badge", "食谱")}
          </Badge>
        </div>
        <h2 className="text-xl font-bold">{getName()}</h2>
        <div className="flex flex-wrap items-center gap-3 mt-3">
          {recipe.cook_time && (
            <div className="flex items-center gap-1.5 text-sm text-muted-foreground">
              <Clock className="h-4 w-4" />
              <span>{recipe.cook_time} {t("recipe.minutes", "分钟")}</span>
            </div>
          )}
          {recipe.servings && (
            <div className="flex items-center gap-1.5 text-sm text-muted-foreground">
              <Users className="h-4 w-4" />
              <span>{recipe.servings} {t("recipe.servingsUnit", "人份")}</span>
            </div>
          )}
          {recipe.difficulty && (
            <Badge variant="outline" className={getDifficultyColor(recipe.difficulty)}>
              <ChefHat className="h-3 w-3 mr-1" />
              {getDifficultyLabel(recipe.difficulty)}
            </Badge>
          )}
        </div>
      </CardHeader>

      <CardContent className="space-y-6">
        {/* Translation loading banner */}
        {needsTranslation && isTranslating && (
          <div className="flex items-center gap-2 p-3 bg-primary/5 border border-primary/20 rounded-lg">
            <Globe className="h-4 w-4 text-primary animate-pulse shrink-0" />
            <AnimatedLoadingText
              messages={[
                t("aiRecipe.translating", "正在翻译食谱内容..."),
                t("aiRecipe.translatingIngredients", "正在翻译配料..."),
                t("aiRecipe.translatingSteps", "正在翻译步骤..."),
              ]}
              interval={2500}
              className="text-primary"
            />
          </div>
        )}

        {(recipe as any).introduction && (
          <p className="text-sm text-muted-foreground whitespace-pre-line">
            {getIntroduction()}
          </p>
        )}

        <Separator />

        {recipe.ingredients && recipe.ingredients.length > 0 && (
          <div>
            <h3 className="font-semibold text-sm mb-3">
              {t("recipe.ingredients", "食材")} ({recipe.ingredients.length})
            </h3>
            <div className="flex items-center text-xs text-muted-foreground font-medium px-2 py-1.5 bg-muted/50 rounded-t-md border border-border/50">
              <span className="flex-1">{t("recipe.ingredientName", "名称")}</span>
              <span className="w-24 text-right">{t("recipe.amount", "用量")}</span>
            </div>
            <ul className="border border-t-0 border-border/50 rounded-b-md divide-y divide-border/50">
              {recipe.ingredients.map((ing, i) => (
                <li key={i} className="flex items-center text-sm px-2 py-2">
                  <span className="flex-1 min-w-0 truncate">{getIngredientName(ing, i)}</span>
                  <span className="w-24 text-right text-muted-foreground shrink-0">
                    {ing.amount} {getIngredientUnit(ing, i)}
                  </span>
                </li>
              ))}
            </ul>
          </div>
        )}

        {viewMode === "guided" && hasSteps && (
          <Button size="lg" className="w-full gap-2 h-14 text-lg" onClick={handleStartCooking}>
            <PlayCircle className="h-6 w-6" />
            {t("recipe.startCooking", "开始烹饪")}
            <Badge variant="secondary" className="ml-2">
              {steps.length} {t("recipe.stepsCount", "步")}
            </Badge>
          </Button>
        )}

        {viewMode === "full" && hasSteps && (
          <>
            <Separator />
            <div>
              <h3 className="font-semibold text-sm mb-3">
                {t("recipe.steps", "步骤")} ({steps.length})
              </h3>
              <ol className="space-y-4">
                {steps.map((step, index) => (
                  <li key={index} className="flex gap-3">
                    <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-xs font-bold">
                      {step.order}
                    </div>
                    <p className="text-sm flex-1">{getStepDescription(step, index)}</p>
                  </li>
                ))}
              </ol>
            </div>
          </>
        )}
      </CardContent>
    </Card>
  );

  if (isMobile) {
    return (
      <Drawer open={open} onOpenChange={handleOpenChange}>
        <DrawerContent className="max-h-[90vh]">
          <DrawerHeader className="flex flex-row items-center justify-between">
            <DrawerTitle className="line-clamp-1 flex-1">{recipeName}</DrawerTitle>
            {onSave && recipe && (
              <Button
                variant="ghost"
                size="sm"
                className={`gap-1.5 shrink-0 ${isSaved ? "text-primary" : ""}`}
                onClick={() => !isSaved && onSave(recipe)}
                disabled={isSaving || isSaved}
              >
                <Bookmark className={`h-4 w-4 ${isSaved ? "fill-primary" : ""}`} />
                {isSaved ? t("aiRecipe.saved", "已保存") : t("aiRecipe.save", "保存")}
              </Button>
            )}
          </DrawerHeader>
          <div className="px-4 pb-6 overflow-y-auto max-h-[78vh]">
            {viewMode === "guided" && guidedPhase === "cooking" && hasSteps ? (
              <CookingContent />
            ) : (
              <>
                <ModeToggle />
                <OverviewContent />
              </>
            )}
          </div>
        </DrawerContent>
      </Drawer>
    );
  }

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent className="max-w-lg max-h-[90vh] overflow-hidden flex flex-col p-0">
        <DialogHeader className="px-6 pt-6 pb-0 flex flex-row items-center justify-between">
          <DialogTitle className="line-clamp-1 flex-1">{recipeName}</DialogTitle>
          {onSave && recipe && (
            <Button
              variant="ghost"
              size="sm"
              className={`gap-1.5 shrink-0 ${isSaved ? "text-primary" : ""}`}
              onClick={() => !isSaved && onSave(recipe)}
              disabled={isSaving || isSaved}
            >
              <Bookmark className={`h-4 w-4 ${isSaved ? "fill-primary" : ""}`} />
              {isSaved ? t("aiRecipe.saved", "已保存") : t("aiRecipe.save", "保存")}
            </Button>
          )}
        </DialogHeader>
        <div className="overflow-y-auto px-6 pb-6 flex-1">
          {viewMode === "guided" && guidedPhase === "cooking" && hasSteps ? (
            <CookingContent />
          ) : (
            <>
              <ModeToggle />
              <OverviewContent />
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default SavedRecipeDetailDialog;
